sed -i 's/<\/body>/    <script src="https:\/\/www.youtube.com\/iframe_api"><\/script>\n    <script>\n        \/\/ Music Player Logic\n        const musicTracks = [\n            {\n                id: "CD-E-LDc384",\n                title: "Metallica Riffs",\n                desc: "High energy metal for intense tactical combinations.",\n                icon: "🎸"\n            },\n            {\n                id: "5qap5aO4i9A",\n                title: "Lofi Girl Radio",\n                desc: "Beats to relax\/study to for deep positional thinking.",\n                icon: "☕"\n            },\n            {\n                id: "pRpeEdMmmQ0",\n                title: "World Cup Music",\n                desc: "Waka Waka! Celebration themes for winning streaks.",\n                icon: "⚽"\n            }\n        ];\n        let currentTrackIndex = 0;\n        let ytPlayer;\n        let isPlaying = false;\n\n        function onYouTubeIframeAPIReady() {\n            ytPlayer = new YT.Player("yt-player", {\n                height: "0",\n                width: "0",\n                videoId: musicTracks[0].id,\n                playerVars: {\n                    "playsinline": 1\n                },\n                events: {\n                    "onReady": onPlayerReady,\n                    "onStateChange": onPlayerStateChange\n                }\n            });\n        }\n\n        function onPlayerReady(event) {\n            \/\/ Ready to play\n        }\n\n        function onPlayerStateChange(event) {\n            if (event.data === YT.PlayerState.PLAYING) {\n                isPlaying = true;\n                updatePlayPauseIcon();\n            } else if (event.data === YT.PlayerState.PAUSED || event.data === YT.PlayerState.ENDED) {\n                isPlaying = false;\n                updatePlayPauseIcon();\n            }\n        }\n\n        function updateTrackUI() {\n            const track = musicTracks[currentTrackIndex];\n            document.getElementById("music-icon").innerText = track.icon;\n            document.getElementById("music-title").innerText = track.title;\n            document.getElementById("music-desc").innerText = track.desc;\n        }\n\n        function updatePlayPauseIcon() {\n            if (isPlaying) {\n                document.getElementById("icon-play").classList.add("hidden");\n                document.getElementById("icon-pause").classList.remove("hidden");\n            } else {\n                document.getElementById("icon-play").classList.remove("hidden");\n                document.getElementById("icon-pause").classList.add("hidden");\n            }\n        }\n\n        document.getElementById("btn-music-play").addEventListener("click", () => {\n            if (ytPlayer && ytPlayer.getPlayerState) {\n                if (isPlaying) {\n                    ytPlayer.pauseVideo();\n                } else {\n                    ytPlayer.playVideo();\n                }\n            }\n        });\n\n        document.getElementById("btn-music-prev").addEventListener("click", () => {\n            currentTrackIndex = (currentTrackIndex - 1 + musicTracks.length) % musicTracks.length;\n            updateTrackUI();\n            if (ytPlayer) {\n                ytPlayer.loadVideoById(musicTracks[currentTrackIndex].id);\n                ytPlayer.playVideo();\n            }\n        });\n\n        document.getElementById("btn-music-next").addEventListener("click", () => {\n            currentTrackIndex = (currentTrackIndex + 1) % musicTracks.length;\n            updateTrackUI();\n            if (ytPlayer) {\n                ytPlayer.loadVideoById(musicTracks[currentTrackIndex].id);\n                ytPlayer.playVideo();\n            }\n        });\n    <\/script>\n<\/body>/g' index.html
